import bisect
import hashlib
from typing import List, Optional, Iterable

class ConsistentHashRing:
    def __init__(self, nodes: Optional[Iterable[str]] = None, replicas: int = 3):
        self.replicas = replicas
        self.ring = dict()
        self.keys = []
        self.nodes = set()
        if nodes:
            for node in nodes:
                self.add_node(node)

