```cpp
template<typename T>
class MPMCQueue {
    struct Cell {
        std::atomic<size_t> seq;
        T data;
    };
    std::vector<Cell> buffer_;
    size_t mask_;
    std::atomic<size_t> head_{0};
    std::atomic<size_t> tail_{0};
public:
    explicit MPMCQueue(size_t cap) {
        size_t c = 1;
        while (c < cap) c <<= 1;
        mask_ = c - 1;
        buffer_.resize(c);
        for (size_t i = 0; i < c; ++i)
            buffer_[i].seq.store(i, std::memory_order_relaxed);
    }
    bool enqueue(T&& val) {
        size_t pos = tail_.fetch_add(1, std::memory_order_relaxed);
        Cell& cell = buffer_[pos & mask_];
        size_t seq = cell.seq.load(std::memory_order_relaxed);
        if (seq != pos) return false;
        cell.data = std::move(val);
        cell.seq.store(pos + 1, std::memory_order_release);
        return true;
    }
    bool dequeue(T& val) {
        size_t pos = head_.fetch_add(1, std::memory_order_relaxed);
        Cell& cell = buffer_[pos & mask_];
        size_t seq = cell.seq.load(std::memory_order_relaxed);
        if (seq != pos + 1) return false;
        val = std::move(cell.data);
        cell.seq.store(pos + mask_ + 1, std::memory_order_relaxed);
        return true;
    }
};
```

ground_truth:
Bugs identified and corrected:

1. **Hole-punching / queue corruption**: `enqueue` and `dequeue` unconditionally advance `tail_` or `head_` with `fetch_add` before confirming the slot is available. Returning `false` after the advance leaves a reserved but never-used slot, permanently corrupting the ring state. The fix uses CAS loops on `tail_` and `head_` so that the index is only advanced after the slot is successfully claimed.

2. **Incorrect memory ordering**: The `seq` loads in both directions use `memory_order_relaxed`, but they act as synchronization points between writer and reader. They must use `memory_order_acquire` to see the `release` stores on the data and the `seq` itself. The dequeue's `seq` store uses `memory_order_relaxed` but must use `memory_order_release` to publish the cleared slot back to writers.

3. **Object lifetime and type punning**: `Cell` contains `T data` by value, which requires `T` to be default-constructible and prevents proper destruction of dequeued items (stale moved-from objects remain). The fix stores objects in `alignas(alignof(T)) std::byte storage[sizeof(T)]` and uses placement-new and explicit destructor calls. This supports non-default-constructible types and ensures destructors run exactly once.

4. **Destruction leak**: The original destructor does not destroy unconsumed elements. The fix loads `head_` and `tail_` in the destructor and explicitly destroys every remaining item.

5. **False sharing**: `head_` and `tail_` are adjacent `std::atomic` members, likely on the same cache line, causing cache-line bouncing between threads. The fix aligns each on a 64-byte boundary with `alignas(64)`.

6. **Exception safety**: If `T`'s move assignment or construction throws after the slot is claimed, the queue is left in an inconsistent state. The corrected implementation adds `static_assert` for nothrow move operations to guarantee lock-free exception safety.

Corrected implementation:

```cpp
#include <atomic>
#include <vector>
#include <cstddef>
#include <type_traits>
#include <new>

template<typename T>
class MPMCQueue {
    struct Cell {
        alignas(alignof(T)) std::byte storage[sizeof(T)];
        std::atomic<size_t> seq{0};

        T* ptr() noexcept { return std::launder(reinterpret_cast<T*>(storage)); }
        void destroy() noexcept { ptr()->~T(); }
    };

    const size_t mask_;
    std::vector<Cell> buffer_;
    alignas(64) std::atomic<size_t> head_{0};
    alignas(64) std::atomic<size_t> tail_{0};

public:
    explicit MPMCQueue(size_t capacity) {
        size_t cap = 1;
        while (cap < capacity) cap <<= 1;
        mask_ = cap - 1;
        buffer_.resize(cap);
        for (size_t i = 0; i < cap; ++i)
            buffer_[i].seq.store(i, std::memory_order_relaxed);
    }

    ~MPMCQueue() {
        size_t h = head_.load(std::memory_order_relaxed);
        size_t t = tail_.load(std::memory_order_relaxed);
        for (size_t i = h; i < t; ++i)
            buffer_[i & mask_].destroy();
    }

    MPMCQueue(const MPMCQueue&) = delete;
    MPMCQueue& operator=(const MPMCQueue&) = delete;

    bool try_enqueue(T&& data) {
        static_assert(std::is_nothrow_move_constructible_v<T>,
                      "T must be nothrow move constructible for lock-free safety");
        while (true) {
            size_t t = tail_.load(std::memory_order_acquire);
            Cell& cell = buffer_[t & mask_];
            size_t seq = cell.seq.load(std::memory_order_acquire);
            if (seq < t) return false;
            if (seq == t) {
                if (tail_.compare_exchange_weak(t, t + 1, std::memory_order_relaxed)) {
                    new (cell.ptr()) T(std::move(data));
                    cell.seq.store(t + 1, std::memory_order_release);
                    return true;
                }
            } else {
                tail_.compare_exchange_weak(t, seq, std::memory_order_relaxed);
            }
        }
    }

    bool try_dequeue(T& data) {
        static_assert(std::is_nothrow_move_assignable_v<T>,
                      "T must be nothrow move assignable for lock-free safety");
        while (true) {
            size_t h = head_.load(std::memory_order_acquire);
            Cell& cell = buffer_[h & mask_];
            size_t seq = cell.seq.load(std::memory_order_acquire);
            if (seq < h + 1) return false;
            if (seq == h + 1) {
                if (head_.compare_exchange_weak(h, h + 1, std::memory_order_relaxed)) {
                    data = std::move(*cell.ptr());
                    cell.destroy();
                    cell.seq.store(h + mask_ + 1, std::memory_order_release);
                    return true;
                }
            } else {
                head_.compare_exchange_weak(h, seq, std::memory_order_relaxed);
            }
        }
    }
};
```

