#include <atomic>
#include <cstddef>
#include <utility>
#include <stdexcept>

template<typename T>
class SharedPtr {
public:
    explicit SharedPtr(T* ptr = nullptr) : ptr_(ptr), count_(nullptr) {
        if (ptr_) {
            try {
                count_ = new std::atomic<std::size_t>(1);
            } catch (...) {
                delete ptr_;
                throw;
            }
        }
    }

    ~SharedPtr() { release(); }

    SharedPtr(const SharedPtr& other) : ptr_(other.ptr_), count_(other.count_) {
        if (count_) {
            count_->fetch_add(1, std::memory_order_relaxed);
        }
    }

    SharedPtr(SharedPtr&& other) noexcept : ptr_(other.ptr_), count_(other.count_) {
        other.ptr_ = nullptr;
        other.count_ = nullptr;
    }

    SharedPtr& operator=(const SharedPtr& other) {
        if (this != &other) {
            if (other.count_) {
                other.count_->fetch_add(1, std::memory_order_relaxed);
            }
            release();
            ptr_ = other.ptr_;
            count_ = other.count_;
        }
        return *this;
    }

    SharedPtr& operator=(SharedPtr&& other) noexcept {
        if (this != &other) {
            release();
            ptr_ = other.ptr_;
            count_ = other.count_;
            other.ptr_ = nullptr;
            other.count_ = nullptr;
        }
        return *this;
    }

    T* operator->() const {
        if (!ptr_) throw std::runtime_error("null dereference");
        return ptr_;
    }

    T& operator*() const {
        if (!ptr_) throw std::runtime_error("null dereference");
        return *ptr_;
    }

    T* get() const noexcept { return ptr_; }
    explicit operator bool() const noexcept { return ptr_ != nullptr; }

    void swap(SharedPtr& other) noexcept {
        using std::swap;
        swap(ptr_, other.ptr_);
        swap(count_, other.count_);
    }

private:
    void release() noexcept {
        if (count_ && count_->fetch_sub(1, std::memory_order_acq_rel) == 1) {
            delete ptr_;
            delete count_;
        }
    }

    T* ptr_;
    std::atomic<std::size_t>* count_;
};
