ground_truth:
Expected issues to identify:
1. **Slice ownership violation**: `slice()` constructs a `Buffer` pointing into the middle of the original allocation. Its destructor will call `delete[]` on a non-array-start pointer, causing undefined behavior and a double-free when the original buffer is destroyed.
2. **Self-append aliasing**: `append()` does not handle `this == &other`. Reallocating deletes the shared buffer, then `memcpy` reads freed memory.
3. **Integer overflow**: `offset + count`, `len + other.len`, and `cap * 2` can overflow `size_t`, wrapping around and bypassing bounds checks or causing allocations smaller than required.
4. **Exception safety**: `resize()`, copy assignment, and `append()` delete the old `ptr` before successfully allocating the new one. If `new` throws, the object is left with a dangling pointer and broken invariants (violating even basic exception safety).
5. **Null pointer memcpy**: The copy constructor and copy assignment pass `other.ptr` to `std::memcpy` when `other` is default-constructed or moved-from (nullptr). `std::memcpy` with a null pointer is undefined behavior even when the length is zero.
6. **Self-move-assignment**: Move assignment does not guard against `this == &other`, resulting in deleting the pointer then reading from the moved-from object (which is now null).
7. **Unsafe cast**: `data()` uses a C-style cast instead of `reinterpret_cast<const char*>()`.
8. **Missing `explicit`**: The `Buffer(size_t)` constructor should be `explicit` to avoid accidental implicit conversions.

Corrected implementation (using `std::unique_ptr` for automatic memory management and strong exception safety):

```cpp
#include <cstdint>
#include <cstring>
#include <algorithm>
#include <stdexcept>
#include <memory>
#include <limits>

class Buffer {
    std::unique_ptr<uint8_t[]> ptr;
    size_t len;
    size_t cap;

    static void checked_memcpy(uint8_t* dest, const uint8_t* src, size_t n) {
        if (n != 0 && dest != nullptr && src != nullptr) {
            std::memcpy(dest, src, n);
        }
    }

public:
    Buffer() noexcept : ptr(nullptr), len(0), cap(0) {}

    explicit Buffer(size_t initial)
        : ptr(initial == 0 ? nullptr : new uint8_t[initial]),
          len(initial), cap(initial) {}

    Buffer(const Buffer& other)
        : ptr(other.len == 0 ? nullptr : new uint8_t[other.cap]),
          len(other.len), cap(other.cap) {
        checked_memcpy(ptr.get(), other.ptr.get(), len);
    }

    Buffer(Buffer&& other) noexcept
        : ptr(std::move(other.ptr)), len(other.len), cap(other.cap) {
        other.len = 0;
        other.cap = 0;
    }

    Buffer& operator=(const Buffer& other) {
        if (this != &other) {
            uint8_t* new_ptr = other.len == 0 ? nullptr : new uint8_t[other.cap];
            checked_memcpy(new_ptr, other.ptr.get(), other.len);
            ptr.reset(new_ptr);
            len = other.len;
            cap = other.cap;
        }
        return *this;
    }

    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            ptr = std::move(other.ptr);
            len = other.len;
            cap = other.cap;
            other.len = 0;
            other.cap = 0;
        }
        return *this;
    }

    ~Buffer() = default;

    Buffer slice(size_t offset, size_t count) const {
        if (offset > len || count > len - offset) {
            throw std::out_of_range("slice");
        }
        Buffer result;
        if (count != 0) {
            result.ptr = std::make_unique<uint8_t[]>(count);
            checked_memcpy(result.ptr.get(), ptr.get() + offset, count);
        }
        result.len = count;
        result.cap = count;
        return result;
    }

    void append(const Buffer& other) {
        if (other.len == 0) return;
        if (this == &other) {
            Buffer copy(other);
            append(copy);
            return;
        }
        size_t new_len = len + other.len;
        if (new_len < len) throw std::length_error("size overflow");
        if (new_len > cap) {
            size_t new_cap = cap;
            if (new_cap == 0) new_cap = 1;
            while (new_cap < new_len) {
                if (new_cap > std::numeric_limits<size_t>::max() / 2) {
                    new_cap = std::numeric_limits<size_t>::max();
                    break;
                }
                new_cap *= 2;
            }
            auto new_ptr = std::make_unique<uint8_t[]>(new_cap);
            checked_memcpy(new_ptr.get(), ptr.get(), len);
            ptr = std::move(new_ptr);
            cap = new_cap;
        }
        checked_memcpy(ptr.get() + len, other.ptr.get(), other.len);
        len = new_len;
    }

    void resize(size_t new_len) {
        if (new_len > cap) {
            auto new_ptr = std::make_unique<uint8_t[]>(new_len);
            checked_memcpy(new_ptr.get(), ptr.get(), len);
            ptr = std::move(new_ptr);
            cap = new_len;
        }
        len = new_len;
    }

    const char* data() const noexcept {
        return reinterpret_cast<const char*>(ptr.get());
    }

    size_t size() const noexcept { return len; }
};
```

Note: An alternative acceptable solution keeps raw pointers but uses copy-and-swap for strong exception safety and ref-counted/shared ownership for zero-copy slices, provided it correctly addresses all UB and safety issues.

