        delete[] data_;
        size_ = other.size_;
        capacity_ = other.capacity_;
        data_ = new T[capacity_];
        std::memcpy(data_, other.data_, size_ * sizeof(T));
        return *this;
    }

    void push_back(const T& value) {
        if (size_ == capacity_) {
            capacity_ = capacity_ == 0 ? 1 : capacity_ * 2;
            T* new_data = new T[capacity_];
            std::memcpy(new_data, data_, size_ * sizeof(T));
            delete[] data_;
            data_ = new_data;
        }
        data_[size_++] = value;
    }

    void pop_back() {
        if (size_ > 0) {
            delete data_[--size_];
        }
    }

    void reserve(size_t new_capacity) {
        if (new_capacity > size_) {
            T* new_data = new T[new_capacity];
            std::memcpy(new_data, data_, size_ * sizeof(T));
            delete[] data_;
            data_ = new_data;
            capacity_ = new_capacity;
        }
    }

    void resize(size_t new_size) {
        reserve(new_size);
        for (size_t i = size_; i < new_size; ++i) {
            data_[i] = T();
        }
        size_ = new_size;
    }

    T& operator[](size_t index) {
        return data_[index];
    }

    size_t size() const { return size_; }
    size_t capacity() const { return capacity_; }

private:
    T* data_ = nullptr;
    size_t size_ = 0;
    size_t capacity_ = 0;
};
```

ground_truth:
Bugs identified:
1. **Copy constructor / assignment / reallocation using `std::memcpy`**: `memcpy` is only valid for trivially copyable types. For non-trivial types (e.g., `std::string`), it copies the internal pointer bitwise without invoking copy constructors, leading to double-free and memory corruption when both the original and copied objects are destroyed.
2. **Array allocation for uninitialized storage**: Using `new T[capacity_]` default-constructs all elements immediately. This prevents storing partially constructed objects (size vs capacity mismatch) and requires `T` to be default constructible. Combined with `memcpy`, it causes double-construction and double-destruction issues.
3. **Move constructor not nulling source**: After moving, `other` retains its `data_` pointer. When `other` is destroyed, it `delete[]`s the same memory, causing a double-free on the moved-from object.
4. **Copy assignment lacks exception safety**: `delete[] data_` is called before `new T[capacity_]` succeeds. If the allocation throws, the object is left with a dangling pointer and invalid state.
5. **`pop_back` uses `delete` on an array element**: `delete data_[--size_]` attempts to deallocate a single object from an array allocation. This is undefined behavior. It should explicitly call the destructor (`data_[--size_].~T()`), but this is only safe if the underlying storage is raw, not an array of live objects.
6. **`reserve` condition and shrink behavior**: The condition `if (new_capacity > size_)` incorrectly triggers reallocation even when `new_capacity` is less than the current `capacity_`, potentially shrinking the buffer and causing unnecessary moves.
7. **`resize` does not destroy excess elements**: When shrinking, it simply updates `size_`, leaving the excess elements alive until the vector is destroyed. For types holding resources (e.g., file handles), this delays cleanup.
8. **No explicit destructor calls during reallocation**: During `push_back`/`reserve` reallocation, `memcpy` is used instead of move/copy construction followed by destruction of old elements. This bypasses move semantics and breaks types with non-trivial copy constructors.

Corrected implementation:
```cpp
#include <algorithm>
#include <type_traits>
#include <utility>

template <typename T>
class SimpleVector {
public:
    SimpleVector() = default;

    ~SimpleVector() {
        clear();
        ::operator delete(data_);
    }

    SimpleVector(const SimpleVector& other)
        : size_(other.size_), capacity_(other.size_) {
        data_ = static_cast<T*>(::operator new(capacity_ * sizeof(T)));
        std::uninitialized_copy(other.begin(), other.end(), data_);
    }

    SimpleVector(SimpleVector&& other) noexcept
        : data_(other.data_), size_(other.size_), capacity_(other.capacity_) {
        other.data_ = nullptr;
        other.size_ = 0;
        other.capacity_ = 0;
    }

    SimpleVector& operator=(const SimpleVector& other) {
        if (this != &other) {
            SimpleVector tmp(other);
            swap(tmp);
        }
        return *this;
    }

    SimpleVector& operator=(SimpleVector&& other) noexcept {
        if (this != &other) {
            clear();
            ::operator delete(data_);
            data_ = other.data_;
            size_ = other.size_;
            capacity_ = other.capacity_;
            other.data_ = nullptr;
            other.size_ = 0;
            other.capacity_ = 0;
        }
        return *this;
    }

    void push_back(const T& value) {
        if (size_ == capacity_) {
            grow();
        }
        new (data_ + size_) T(value);
        ++size_;
    }

    void push_back(T&& value) {
        if (size_ == capacity_) {
            grow();
        }
        new (data_ + size_) T(std::move(value));
        ++size_;
    }

    void pop_back() {
        if (size_ > 0) {
            data_[--size_].~T();
        }
    }

    void reserve(size_t new_capacity) {
        if (new_capacity > capacity_) {
            reallocate(new_capacity);
        }
    }

    void resize(size_t new_size) {
        if (new_size < size_) {
            for (size_t i = new_size; i < size_; ++i) {
                data_[i].~T();
            }
        } else if (new_size > size_) {
            reserve(new_size);
            for (size_t i = size_; i < new_size; ++i) {
                new (data_ + i) T();
            }
        }
        size_ = new_size;
    }

    void clear() {
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }
        size_ = 0;
    }

    T& operator[](size_t index) { return data_[index]; }
    const T& operator[](size_t index) const { return data_[index]; }

    T* begin() { return data_; }
    const T* begin() const { return data_; }
    T* end() { return data_ + size_; }
    const T* end() const { return data_ + size_; }

    size_t size() const { return size_; }
    size_t capacity() const { return capacity_; }
    bool empty() const { return size_ == 0; }

    void swap(SimpleVector& other) noexcept {
        using std::swap;
        swap(data_, other.data_);
        swap(size_, other.size_);
        swap(capacity_, other.capacity_);
    }

private:
    T* data_ = nullptr;
    size_t size_ = 0;
    size_t capacity_ = 0;

    void grow() {
        reallocate(capacity_ == 0 ? 1 : capacity_ * 2);
    }

    void reallocate(size_t new_capacity) {
        T* new_data = static_cast<T*>(::operator new(new_capacity * sizeof(T)));

        for (size_t i = 0; i < size_; ++i) {
            new (new_data + i) T(std::move_if_noexcept(data_[i]));
            data_[i].~T();
        }

        ::operator delete(data_);
        data_ = new_data;
        capacity_ = new_capacity;
    }
};
```

