```python
import time
import threading
from functools import wraps

def timed_lru_cache(timeout=60, maxsize=128):
    cache = {}
    timestamps = {}
    locks = {}

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = hash((args, tuple(kwargs.items())))

            if key not in locks:
                locks[key] = threading.Lock()

            with locks[key]:
                now = time.time()
                if key in cache and now - timestamps[key] > timeout:
                    del cache[key]
                    del timestamps[key]

                if key in cache:
                    timestamps[key] = now
                    return cache[key]

                result = func(*args, **kwargs)

                expired = [k for k, ts in timestamps.items() if now - ts > timeout]
                for k in expired:
                    del cache[k]
                    del timestamps[k]

                while len(cache) >= maxsize:
                    oldest = min(timestamps, key=timestamps.get)
                    del cache[oldest]
                    del timestamps[oldest]

                cache[key] = result
                timestamps[key] = now
                return result
        return wrapper
    return decorator
