#include <atomic>
#include <utility>

template<typename T>
class SharedPtr {
    struct ControlBlock {
        T* ptr;
        std::atomic<int> ref_count;
        explicit ControlBlock(T* p) : ptr(p), ref_count(1) {}
    };
    ControlBlock* ctrl;
    void release() {
        if (ctrl && --ctrl->ref_count == 0) {
            delete ctrl->ptr;
            delete ctrl;
        }
    }
public:
    explicit SharedPtr(T* p = nullptr) : ctrl(p ? new ControlBlock(p) : nullptr) {}
    ~SharedPtr() { release(); }
    SharedPtr(const SharedPtr& other) : ctrl(other.ctrl) {
        if (ctrl) ++ctrl->ref_count;
    }
    SharedPtr(SharedPtr&& other) noexcept : ctrl(other.ctrl) {
        other.ctrl = nullptr;
